    {SIGSEGV, "SIGSEGV", "CORE", 1},
    {SIGTERM, "SIGTERM", "TERM", 1},
    {SIGKILL, "SIGKILL", "TERM", 0},
    {SIGSTOP, "SIGSTOP", "STOP", 0},
    {SIGCHLD, "SIGCHLD", "IGN",  1},
    {SIGCONT, "SIGCONT", "CONT", 1},
};
#define TABLE_SIZE (sizeof(table)/sizeof(table[0]))
const SigEntry *find_by_num(int num) {
    for (size_t i = 0; i < TABLE_SIZE; i++)
        if (table[i].num == num) return &table[i];
    return NULL;
}
int main(void) {
    printf("%-4s %-10s %-6s %s\n", "NUM", "NAME", "DISP", "CATCHABLE");
    for (size_t i = 0; i < TABLE_SIZE; i++)
        printf("%-4d %-10s %-6s %s\n",
            table[i].num, table[i].name, table[i].disp,
            table[i].catchable ? "oui" : "NON");
    const SigEntry *e = find_by_num(SIGKILL);
    if (e)
        printf("\n%s (signal %d): catchable=%s\n", e->name, e->num, e->catchable ? "oui" : "NON");
    return 0;
}

